class Solution:
    def earliestSecondToMarkIndices(self, nums, changeIndices):
        n, m = len(nums), len(changeIndices)
        def feasible(T):
            last = [-1] * (n + 1)
            for s in range(T):
                last[changeIndices[s]] = s
            if any(last[i] == -1 for i in range(1, n + 1)):
                return False
            marking = sorted((last[i], i) for i in range(1, n + 1))
            free = 0
            prev = 0
            for pos, idx in marking:
                free += pos - prev
                if free < nums[idx - 1]:
                    return False
                free -= nums[idx - 1]
                prev = pos + 1
            return True
        for T in range(1, m + 1):
            if feasible(T):
                return T
        return -1

