var earliestSecondToMarkIndices = function(nums, changeIndices) {
    const n = nums.length, m = changeIndices.length;
    function feasible(T) {
        const last = new Array(n + 1).fill(-1);
        for (let s = 0; s < T; s++) last[changeIndices[s]] = s;
        for (let i = 1; i <= n; i++) if (last[i] === -1) return false;
        const marking = [];
        for (let i = 1; i <= n; i++) marking.push([last[i], i]);
        marking.sort((a, b) => a[0] - b[0]);
        let free = 0, prev = 0;
        for (const [pos, idx] of marking) {
            free += pos - prev;
            if (free < nums[idx - 1]) return false;
            free -= nums[idx - 1];
            prev = pos + 1;
        }
        return true;
    }
    let lo = 1, hi = m, ans = -1;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (feasible(mid)) { ans = mid; hi = mid - 1; }
        else lo = mid + 1;
    }
    return ans;
};
